// ── INIT PIPELINE STATE ──────────────────────────────────
// Validate input and initialise state object passed through the pipeline.

const body = $input.first().json.body || $input.first().json;

const brand = body.brand || 'reflexion';
const keyword = body.keyword;
const pipeline_run_id = body.pipeline_run_id || crypto.randomUUID();
const brief = body.brief || {};
const max_words = body.max_words || 1500;

if (!keyword) throw new Error('keyword is required');

// State object travels through all nodes
return [{
  json: {
    brand,
    keyword,
    pipeline_run_id,
    brief,
    max_words,
    revision_count: 0,
    max_revisions: 2,
    stage: 'init',
    started_at: new Date().toISOString(),
  }
}];

// ── MERGE RAG CONTEXT ────────────────────────────────────
// Combine obsidian + faq results into a single context string for Writer.

const state = $('Init State').first().json;
const obsidianResults = $('RAG — Obsidian Vault').first().json.results || [];
const faqResults = $('RAG — FAQ Knowledge').first().json.results || [];

const formatChunks = (items, label) =>
  items.map((r, i) =>
    `[${label} ${i+1} | score:${r.score} | ${r.payload?.file_path || r.payload?.source || 'vault'}]\n${r.text}`
  ).join('\n\n');

const rag_context = [
  obsidianResults.length ? `## Obsidian Vault Context\n${formatChunks(obsidianResults, 'VAULT')}` : '',
  faqResults.length ? `## Published Articles (avoid duplication)\n${formatChunks(faqResults, 'PUBLISHED')}` : '',
].filter(Boolean).join('\n\n');

return [{
  json: {
    ...state,
    rag_context,
    rag_obsidian_count: obsidianResults.length,
    rag_faq_count: faqResults.length,
    stage: 'rag_ready',
  }
}];

// ── PASS DRAFT TO NEXT STAGE ────────────────────────────
const state = $('Merge RAG Context').first().json;
const writer = $input.first().json;

if (!writer.content) throw new Error('Writer returned empty content');

return [{
  json: {
    ...state,
    draft: writer.content,
    title: writer.title,
    meta_description: writer.meta_description,
    slug: writer.slug,
    schema_markup: writer.schema_markup,
    internal_links_used: writer.internal_links_used,
    word_count: writer.word_count,
    writer_model: writer.model_used,
    prompt_hash: writer.prompt_hash,
    stage: 'written',
  }
}];

const state = $('After Writer').first().json;
const human = $input.first().json;

return [{
  json: {
    ...state,
    draft: human.humanized || state.draft,
    humanizer_changes: human.changes_count,
    humanizer_patterns: human.patterns_eliminated,
    stage: 'humanized',
  }
}];

// ── CRITIC ROUTING ────────────────────────────────────────
// HIGH severity findings → route to revision loop
// approved_for_next_stage → proceed to QC

const state = $('After Humanizer').first().json;
const critic = $input.first().json;

const high_count = critic.high_severity_count || 0;
const approved = critic.approved_for_next_stage !== false;

// Build revision feedback from high-severity findings
let revision_feedback = null;
if (high_count > 0) {
  const high_findings = (critic.findings || []).filter(f => f.severity === 'high');
  revision_feedback = high_findings.map(f =>
    `[${f.type.toUpperCase()}] ${f.critique}\n→ Fix: ${f.fix_suggestion}`
  ).join('\n\n');
}

return [{
  json: {
    ...state,
    critic_verdict: critic.overall_verdict,
    critic_high_count: high_count,
    critic_approved: approved,
    critic_summary: critic.debate_summary,
    revision_feedback: revision_feedback || state.revision_feedback,
    stage: approved ? 'critic_approved' : 'critic_revision_needed',
  }
}];

const state = $json;
return [{
  json: {
    ...state,
    revision_count: (state.revision_count || 0) + 1,
    stage: 'revision_loop',
  }
}];

// ── QC DECISION ROUTING ─────────────────────────────────
const state = $('Critic Router').first().json;
const qc = $input.first().json;

return [{
  json: {
    ...state,
    qc_decision:        qc.decision,
    qc_weighted_score:  qc.weighted_score,
    qc_min_score:       qc.min_score,
    qc_scores:          qc.scores,
    qc_revision_instr:  qc.revision_instructions,
    qc_escalation_rsn:  qc.escalation_reason,
    qc_strengths:       qc.strengths,
    revision_feedback:  qc.revision_instructions || state.revision_feedback,
    stage: `qc_${qc.decision.toLowerCase()}`,
  }
}];

// ── BUILD SLACK APPROVAL MESSAGE ────────────────────────
// APPROVED: fast-track Approve+Publish button
// Shows QC scores bar chart in ASCII for quick visual scan

const s = $json;
const scores = s.qc_scores || {};

const scoreBar = (score) => {
  const filled = Math.round(score);
  return '█'.repeat(filled) + '░'.repeat(10 - filled) + ` ${score.toFixed(1)}`;
};

const dimEmoji = (score) => score >= 8.5 ? '✅' : score >= 7 ? '🟡' : '❌';

const scoreLines = Object.entries(scores).map(([dim, s]) =>
  `${dimEmoji(s.score)} *${dim.replace(/_/g,' ')}* ${scoreBar(s.score)}`
).join('\n');

const message = {
  channel: 'C023FGKE9AP',
  text: `🟢 QC APPROVED — ${s.brand.toUpperCase()} | ${s.keyword}`,
  blocks: [
    {
      type: 'header',
      text: { type: 'plain_text', text: `✅ Article Ready: ${s.title || s.keyword}` }
    },
    {
      type: 'section',
      fields: [
        { type: 'mrkdwn', text: `*Brand:* ${s.brand}` },
        { type: 'mrkdwn', text: `*Keyword:* ${s.keyword}` },
        { type: 'mrkdwn', text: `*QC Score:* ${s.qc_weighted_score}/10` },
        { type: 'mrkdwn', text: `*Words:* ${s.word_count || '—'}` },
        { type: 'mrkdwn', text: `*Revisions:* ${s.revision_count}` },
        { type: 'mrkdwn', text: `*Critic:* ${s.critic_verdict || '—'}` },
      ]
    },
    {
      type: 'section',
      text: { type: 'mrkdwn', text: `*QC Scores:*\n\`\`\`\n${scoreLines}\n\`\`\`` }
    },
    {
      type: 'section',
      text: { type: 'mrkdwn', text: `*Strengths:* ${(s.qc_strengths || []).join(' · ')}` }
    },
    {
      type: 'actions',
      elements: [
        {
          type: 'button', style: 'primary',
          text: { type: 'plain_text', text: '🚀 Approve + Publish' },
          value: JSON.stringify({ action: 'approve_publish', pipeline_run_id: s.pipeline_run_id, brand: s.brand }),
          action_id: 'approve_publish'
        },
        {
          type: 'button',
          text: { type: 'plain_text', text: '✏️ Edit Draft' },
          url: `https://n8n.recall-agency.com/workflow/wf021-edit?run=${s.pipeline_run_id}`,
          action_id: 'edit_draft'
        },
        {
          type: 'button', style: 'danger',
          text: { type: 'plain_text', text: '🗑️ Reject' },
          value: JSON.stringify({ action: 'reject', pipeline_run_id: s.pipeline_run_id }),
          action_id: 'reject'
        }
      ]
    }
  ]
};

return [{ json: { ...s, slack_payload: message, stage: 'awaiting_human_approval' } }];

// ── NEEDS REVISION — check retry count ──────────────────
const s = $json;
const can_retry = (s.revision_count || 0) < (s.max_revisions || 2);
return [{ json: { ...s, can_retry, stage: can_retry ? 'revision_loop' : 'max_revisions_reached' } }];

// ── ESCALATE SLACK MESSAGE ──────────────────────────────
const s = $json;

const low_scores = Object.entries(s.qc_scores || {})
  .filter(([_, sc]) => sc.score < 7.0)
  .map(([dim, sc]) => `• *${dim}*: ${sc.score}/10 — ${sc.issues?.join(', ') || sc.justification?.slice(0,80)}`)
  .join('\n');

const message = {
  channel: 'C023FGKE9AP',
  text: `🔴 ESCALATION REQUIRED — ${s.brand.toUpperCase()} | ${s.keyword}`,
  blocks: [
    { type: 'header', text: { type: 'plain_text', text: '🚨 QC Escalation — Human Review Required' } },
    {
      type: 'section',
      fields: [
        { type: 'mrkdwn', text: `*Brand:* ${s.brand}` },
        { type: 'mrkdwn', text: `*Keyword:* ${s.keyword}` },
        { type: 'mrkdwn', text: `*QC Score:* ${s.qc_weighted_score}/10 ❌` },
        { type: 'mrkdwn', text: `*Revisions:* ${s.revision_count}/${s.max_revisions}` },
      ]
    },
    {
      type: 'section',
      text: { type: 'mrkdwn', text: `*Reason:* ${s.qc_escalation_rsn || s.qc_revision_instr || 'Score below threshold'}\n\n*Failing Dimensions:*\n${low_scores}` }
    },
    {
      type: 'actions',
      elements: [
        {
          type: 'button', style: 'danger',
          text: { type: 'plain_text', text: '👁️ Review Full Draft' },
          value: JSON.stringify({ action: 'review', pipeline_run_id: s.pipeline_run_id }),
          action_id: 'review_escalated'
        }
      ]
    }
  ]
};

return [{ json: { ...s, slack_payload: message, stage: 'escalated' } }];
